$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$TASK_ISSUE = "36"
$TIMEOUT = 900
$INTERVAL = 30
$ELAPSED = 0
$PR_NUMBER = $null

while ($ELAPSED -lt $TIMEOUT) {
    # Strategy A: issue timeline
    try {
        $timeline = gh api "/repos/$REPO/issues/$TASK_ISSUE/timeline" --jq '.[] | select(.event == \"cross-referenced\") | select(.source.issue.pull_request != null) | select(.source.issue.state == \"open\") | .source.issue.number' 2>$null
        if ($timeline) {
            $PR_NUMBER = ($timeline -split "`n" | Select-Object -First 1).Trim()
        }
    } catch {}

    # Strategy B: PR body search
    if (-not $PR_NUMBER) {
        try {
            $bodySearch = gh pr list -R $REPO --state open --json number,body --jq ".[] | select(.body | test(`\"#$TASK_ISSUE`\")) | .number" 2>$null
            if ($bodySearch) {
                $PR_NUMBER = ($bodySearch -split "`n" | Select-Object -First 1).Trim()
            }
        } catch {}
    }

    # Strategy C: title/branch match
    if (-not $PR_NUMBER) {
        try {
            $titleSearch = gh pr list -R $REPO --state open --json number,title,headRefName --jq ".[] | select((.title | test(`\"$TASK_ISSUE`\"; `\"i`\")) or (.headRefName | test(`\"$TASK_ISSUE`\"))) | .number" 2>$null
            if ($titleSearch) {
                $PR_NUMBER = ($titleSearch -split "`n" | Select-Object -First 1).Trim()
            }
        } catch {}
    }

    if ($PR_NUMBER) {
        Write-Host "Found PR #$PR_NUMBER"
        break
    }

    Write-Host "No PR found yet. Elapsed: ${ELAPSED}s / ${TIMEOUT}s. Sleeping ${INTERVAL}s..."
    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

if (-not $PR_NUMBER) {
    Write-Host "TIMEOUT: No PR found after ${TIMEOUT}s"
} else {
    Write-Host "PR_NUMBER=$PR_NUMBER"
    # Verify base branch
    $actualBase = gh pr view $PR_NUMBER -R $REPO --json baseRefName --jq '.baseRefName'
    Write-Host "Base branch: $actualBase"
    # Get the head branch
    $headBranch = gh pr view $PR_NUMBER -R $REPO --json headRefName --jq '.headRefName'
    Write-Host "Head branch: $headBranch"
}

