$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$PR_NUMBER = "46"
$BRANCH = "copilot/edburns28-python-agent-demo"
$TIMEOUT = 600
$INTERVAL = 30
$ELAPSED = 0

# Wait for Copilot cloud agent to finish and CI checks to appear
while ($ELAPSED -lt $TIMEOUT) {
    # Check if Copilot cloud agent is still running
    $runs = gh run list -R $REPO --branch $BRANCH --json databaseId,name,status,conclusion -L 5 2>$null | ConvertFrom-Json
    $ccaRunning = $runs | Where-Object { $_.name -eq "Running Copilot cloud agent" -and $_.status -eq "in_progress" }

    if (-not $ccaRunning) {
        Write-Host "Copilot cloud agent finished."
    }

    # Check for PR checks
    $checksOutput = gh pr checks $PR_NUMBER -R $REPO 2>&1
    if ($checksOutput -notmatch "no checks reported") {
        Write-Host "CI checks appeared:"
        Write-Host $checksOutput
        break
    }

    # Check for action_required runs
    $actionReq = $runs | Where-Object { $_.status -eq "action_required" }
    if ($actionReq) {
        Write-Host "Found action_required runs:"
        $actionReq | ForEach-Object { Write-Host "$($_.databaseId) $($_.name)" }
        break
    }

    Write-Host "Waiting for CI checks... Elapsed: ${ELAPSED}s. CCA running: $([bool]$ccaRunning)"
    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

if ($ELAPSED -ge $TIMEOUT) {
    Write-Host "Still waiting after ${TIMEOUT}s. Checking latest state..."
    gh run list -R $REPO --branch $BRANCH --json databaseId,name,status,conclusion -L 10 --jq '.[] | "\(.databaseId) \(.status) \(.conclusion) \(.name)"'
    gh pr checks $PR_NUMBER -R $REPO 2>&1
}

